(function(global){
  'use strict';

  function normalizeBytes(input){
    if (input instanceof Uint8Array) return input;
    if (input instanceof ArrayBuffer) return new Uint8Array(input);
    if (ArrayBuffer.isView(input)) return new Uint8Array(input.buffer.slice(input.byteOffset, input.byteOffset + input.byteLength));
    throw new Error('Unsupported PDF bytes');
  }

  function dataUrlToUint8Array(dataUrl){
    var base64 = String(dataUrl).split(',')[1] || '';
    var binary = atob(base64);
    var len = binary.length;
    var bytes = new Uint8Array(len);
    for (var i = 0; i < len; i++) bytes[i] = binary.charCodeAt(i);
    return bytes;
  }

  function loadImage(dataUrl){
    return new Promise(function(resolve, reject){
      var img = new Image();
      img.onload = function(){ resolve(img); };
      img.onerror = reject;
      img.src = dataUrl;
    });
  }

  function chooseRenderScale(){
    var dpr = Math.max(1, Math.min(2, global.devicePixelRatio || 1));
    var mobile = /Android|iPhone|iPad|iPod|Mobile/i.test(global.navigator && global.navigator.userAgent || '');
    return mobile ? Math.min(1.5, dpr) : Math.min(2, Math.max(1.35, dpr));
  }

  function drawOverlayForRotation(ctx, img, canvasWidth, canvasHeight, rotation){
    var angle = ((rotation % 360) + 360) % 360;
    ctx.save();
    if (angle === 90) {
      ctx.translate(canvasWidth, 0);
      ctx.rotate(Math.PI / 2);
      ctx.drawImage(img, 0, 0, canvasHeight, canvasWidth);
    } else if (angle === 180) {
      ctx.translate(canvasWidth, canvasHeight);
      ctx.rotate(Math.PI);
      ctx.drawImage(img, 0, 0, canvasWidth, canvasHeight);
    } else if (angle === 270) {
      ctx.translate(0, canvasHeight);
      ctx.rotate(-Math.PI / 2);
      ctx.drawImage(img, 0, 0, canvasHeight, canvasWidth);
    } else {
      ctx.drawImage(img, 0, 0, canvasWidth, canvasHeight);
    }
    ctx.restore();
  }

  function buildPdfFromJpegs(pages){
    var encoder = new TextEncoder();
    var parts = [];
    var offsets = [];
    var pos = 0;

    function pushBytes(bytes){
      parts.push(bytes);
      pos += bytes.length;
    }

    function pushText(text){
      pushBytes(encoder.encode(text));
    }

    function beginObj(id){
      offsets[id] = pos;
      pushText(id + ' 0 obj\n');
    }

    function endObj(){
      pushText('endobj\n');
    }

    pushText('%PDF-1.4\n%\xFF\xFF\xFF\xFF\n');

    var pageRefs = [];
    var objId = 3;
    for (var i = 0; i < pages.length; i++) {
      pageRefs.push({ page: objId, image: objId + 1, content: objId + 2 });
      objId += 3;
    }
    var size = objId;

    beginObj(1);
    pushText('<< /Type /Catalog /Pages 2 0 R >>\n');
    endObj();

    beginObj(2);
    pushText('<< /Type /Pages /Count ' + pages.length + ' /Kids [' + pageRefs.map(function(ref){ return ref.page + ' 0 R'; }).join(' ') + '] >>\n');
    endObj();

    for (var p = 0; p < pages.length; p++) {
      var page = pages[p];
      var refs = pageRefs[p];
      var imageName = '/Im' + (p + 1);
      var content = 'q\n' + page.pageWidth.toFixed(4) + ' 0 0 ' + page.pageHeight.toFixed(4) + ' 0 0 cm\n' + imageName + ' Do\nQ\n';
      var contentBytes = encoder.encode(content);

      beginObj(refs.page);
      pushText('<< /Type /Page /Parent 2 0 R /MediaBox [0 0 ' + page.pageWidth.toFixed(4) + ' ' + page.pageHeight.toFixed(4) + '] ' +
               '/Resources << /ProcSet [/PDF /ImageC] /XObject << ' + imageName + ' ' + refs.image + ' 0 R >> >> ' +
               '/Contents ' + refs.content + ' 0 R >>\n');
      endObj();

      beginObj(refs.image);
      pushText('<< /Type /XObject /Subtype /Image /Width ' + page.imageWidth + ' /Height ' + page.imageHeight + ' ' +
               '/ColorSpace /DeviceRGB /BitsPerComponent 8 /Filter /DCTDecode /Length ' + page.jpegBytes.length + ' >>\nstream\n');
      pushBytes(page.jpegBytes);
      pushText('\nendstream\n');
      endObj();

      beginObj(refs.content);
      pushText('<< /Length ' + contentBytes.length + ' >>\nstream\n');
      pushBytes(contentBytes);
      pushText('endstream\n');
      endObj();
    }

    var xrefStart = pos;
    pushText('xref\n0 ' + size + '\n');
    pushText('0000000000 65535 f \n');
    for (var id = 1; id < size; id++) {
      var off = String(offsets[id] || 0).padStart(10, '0');
      pushText(off + ' 00000 n \n');
    }
    pushText('trailer\n<< /Size ' + size + ' /Root 1 0 R >>\nstartxref\n' + xrefStart + '\n%%EOF');

    var out = new Uint8Array(pos);
    var cursor = 0;
    for (var partIndex = 0; partIndex < parts.length; partIndex++) {
      out.set(parts[partIndex], cursor);
      cursor += parts[partIndex].length;
    }
    return out;
  }

  async function exportAnnotatedPdf(options){
    var pdfjs = global.pdfjsLib;
    if (!pdfjs || !pdfjs.getDocument) {
      throw new Error('PDF.js is required before exporting PDF.');
    }
    var pdfBytes = normalizeBytes(options.pdfBytes);
    var renderOverlayForPage = options.renderOverlayForPage;
    var onProgress = typeof options.onProgress === 'function' ? options.onProgress : function(){};
    var pdfDoc = await pdfjs.getDocument({ data: pdfBytes }).promise;
    var renderScale = chooseRenderScale();
    var renderedPages = [];

    for (var i = 0; i < pdfDoc.numPages; i++) {
      var pageNumber = i + 1;
      onProgress('جاري تجهيز صفحة ' + pageNumber + ' من ' + pdfDoc.numPages + '...');
      var page = await pdfDoc.getPage(pageNumber);
      var baseWidth = Math.abs(page.view[2] - page.view[0]);
      var baseHeight = Math.abs(page.view[3] - page.view[1]);
      var rotation = ((page.rotate % 360) + 360) % 360;
      var viewport = page.getViewport({ scale: renderScale });
      var canvas = document.createElement('canvas');
      canvas.width = Math.max(1, Math.round(viewport.width));
      canvas.height = Math.max(1, Math.round(viewport.height));
      var ctx = canvas.getContext('2d', { alpha: false, willReadFrequently: false });
      if (!ctx) throw new Error('Unable to create canvas context for PDF export.');

      await page.render({ canvasContext: ctx, viewport: viewport }).promise;

      if (typeof renderOverlayForPage === 'function') {
        var overlayDataUrl = await renderOverlayForPage({
          pageNumber: pageNumber,
          pageWidth: baseWidth,
          pageHeight: baseHeight,
          rotation: rotation,
          viewportWidth: viewport.width,
          viewportHeight: viewport.height,
          renderScale: renderScale,
        });
        if (overlayDataUrl) {
          var overlayImage = await loadImage(overlayDataUrl);
          drawOverlayForRotation(ctx, overlayImage, canvas.width, canvas.height, rotation);
        }
      }

      var jpegDataUrl = canvas.toDataURL('image/jpeg', 0.92);
      renderedPages.push({
        pageWidth: viewport.width / renderScale,
        pageHeight: viewport.height / renderScale,
        imageWidth: canvas.width,
        imageHeight: canvas.height,
        jpegBytes: dataUrlToUint8Array(jpegDataUrl),
      });
    }

    return buildPdfFromJpegs(renderedPages);
  }

  global.EssamPdfExport = { exportAnnotatedPdf: exportAnnotatedPdf };
})(typeof window !== 'undefined' ? window : self);
